use UNISIM.VCOMPONENTS.ALL;
entity design_1_microblaze_mcs_0_0_Iomodule_core is
  port (
    UART_Tx : out STD_LOGIC;
    GPO1 : out STD_LOGIC_VECTOR ( 0 to 0 );
    GPO2 : out STD_LOGIC_VECTOR ( 0 to 0 );
    \lmb_abus_Q_reg[5]\ : out STD_LOGIC;
    Sl_DBus : out STD_LOGIC_VECTOR ( 7 downto 0 );
    Clk : in STD_LOGIC;
    Rst : in STD_LOGIC;
    UART_Rx : in STD_LOGIC;
    Q : in STD_LOGIC_VECTOR ( 5 downto 0 );
    lmb_reg_read : in STD_LOGIC;
    GPI1 : in STD_LOGIC_VECTOR ( 0 to 0 );
    lmb_reg_write : in STD_LOGIC;
    E : in STD_LOGIC_VECTOR ( 0 to 0 );
    D : in STD_LOGIC_VECTOR ( 7 downto 0 );
    io_bus_read_data : in STD_LOGIC_VECTOR ( 7 downto 0 )
  );
end design_1_microblaze_mcs_0_0_Iomodule_core;

architecture STRUCTURE of design_1_microblaze_mcs_0_0_Iomodule_core is
  signal GPI_In : STD_LOGIC_VECTOR ( 0 to 0 );
  signal GPO_I2_n_1 : STD_LOGIC;
begin
GPI_I1: entity work.design_1_microblaze_mcs_0_0_GPI_Module
     port map (
      Clk => Clk,
      GPI1(0) => GPI1(0),
      GPI_In(0) => GPI_In(0),
      Q(4 downto 0) => Q(4 downto 0),
      \lmb_abus_Q_reg[5]\ => \lmb_abus_Q_reg[5]\,
