      Clk => Clk,
      D(0) => D(0),
      GPO1(0) => GPO1(0),
      Q(1) => Q(3),
      Q(0) => Q(0),
      Rst => Rst,
      \TMR_No.gpo_io_i_reg[0]_0\ => GPO_I2_n_1
    );
GPO_I2: entity work.design_1_microblaze_mcs_0_0_GPO_Module_714
     port map (
      Clk => Clk,
      D(0) => D(0),
      GPO2(0) => GPO2(0),
