      Rst => Rst,
      \lmb_abus_Q_reg[2]\ => GPO_I2_n_1,
      lmb_reg_write => lmb_reg_write
    );
UART_I1: entity work.design_1_microblaze_mcs_0_0_UART
     port map (
      Clk => Clk,
      D(7 downto 0) => D(7 downto 0),
      E(0) => E(0),
